VALUES
  ('social-worker-moex-01991', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會救助法對於低收入的認定，必須由戶籍所在地直轄市、縣（市）主管機關審核，符合家庭總收 入平均分配全家人口，每人每月在最低生活費以下，且家庭財產未超過中央、直轄市主管機關公告之當 年度一定金額者。該法有關最低生活費的設定，較符合以下那一個選項的論點？', '["絕對貧窮", "相對貧窮", "社會排除", "社會隔離"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01992', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '英國學者Richard M. Titmuss指出社會服務（現金與實物給付）是具有多元目標的多元體系。他認為多數', '["志願服務 體系", "家庭福利體系", "職業福利體系", "財稅福利體系  ⑤社會福利體系"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01993', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '「失業認定」是我國就業保險法之被保險人得以領取失業給付的行政判斷。在失業認定時，下列那一項 不符合請領失業給付的資格？', '["被保險人在辦理退保當日前3年內，保險年資合計必須滿6個月以上", "被保險人必須提出雇主開具的「非自願性失業證明」", "被保險人不接受工資低於其每月得請領失業給付數額之推介工作", "被保險人向公立就業服務機構辦理求職登記，經14天等待期仍無法推介就業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01994', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '某高職學校的行政主管運用權勢，要求辦公室一位女性約聘員工跟他交往，並以考績表現及未來繼續聘 任要脅。這位女性員工感覺到被性騷擾及威脅，想要提出申訴。請問以上述的情況所造成的騷擾，適用 的法律是以下那一個？', '["性別教育平等法", "性別工作平等法", "性騷擾防治法", "性騷擾暴力防治法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01995', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '以「生命歷程觀點」（life course perspective）來探討與檢視身心障礙者的健康照顧政策，下面那一個選 項最為貼近該觀點的論述？', '["障礙者在不同年齡階段都有類似的基本健康與醫療服務需求；隨著年齡越大，醫療服務需求也越多", "身心障礙者的身心功能之復原狀況，受到其在醫療歷程的治療與復健經驗深深影響", "先天障礙者與後天障礙者，其障礙經驗與健康醫療需求不相同", "不同世代的障礙者在不同的歷史事件與社會經濟環境影響下，其所經歷的健康醫療與障礙經驗也不相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01996', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '人民的居住正義是民國 100 年社會福利政策綱領的重要主張。以下有關社會住宅的相關選項，那一個選 項是不正確的？', '["新修正的「住宅法」是在106年公布實施的", "住宅法中所定義的社會住宅是指由政府興辦或獎勵民間興辦，供出租或在政府規範下買賣作非營利用 途的住宅", "依照新住宅法的規範，社會住宅應以直轄市、縣（市）轄區為計算範圍，提供至少百分之三十以上比 率出租給經濟或社會弱勢者", "對於未設籍在當地，但在該地區就學、就業有居住需求的民眾，政府或民間興建的社會住宅應提供一 定比率協助之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01997', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國相關法令中，對於弱勢民眾遭遇不合理對待、剝削、遺棄等緊急狀況而有危及生命安全與健康之情 形，均責成醫事人員、社會工作人員、警察人員、村里幹事或其他相關業務之執行人員負有向當地直轄 市、縣（市）主管機關通報之義務。在下列四個選項中，那一個選項與法令規定不合？', '["根據身心障礙者權益保障法之規定，當上述人員知悉身心障礙者有遭受遺棄之情形，應立即向直轄市、 縣（市）主管機關通報，至遲不得超過24小時", "根據兒童及少年福利與權益保障法之規定，當上述人員於執行職務時知悉兒童或少年有遭受遺棄之情 形，應立即向直轄市、縣（市）主管機關通報，至遲不得超過24小時", "根據老人福利法之規定，當上述人員於執行職務時知悉老人有遭受遺棄之情形，應立即向直轄市、縣 （市）主管機關通報，至遲不得超過24小時", "根據家庭暴力防治法之規定，當上述人員在執行職務時知悉有疑似家庭暴力，應立即通報當地主管機 關，至遲不得逾24小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01998', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會保險的保險費率，下列那一項是採用「實績費率」？', '["勞工的醫療健康保險", "勞工的失業保險", "勞工的職業災害保險", "勞工的退休保險"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01999', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '老人福利法第2章經濟安全條文，下列所示何者錯誤？', '["中低收入戶老人未接受收容安置者，得申請發給生活津貼。不符合請領資格而領取津貼者，其領得之 津貼經主管機關告知，應於事實發生之日起50日內繳還，未繳還者依法移送行政執行", "依本法請領各項現金給付或補助之權利，不得扣押、讓與或提供擔保", "為保護老人之財產安全，各級主管機關應鼓勵其將財產交付信託", "金融主管機關應鼓勵信託業者及金融業者辦理財產信託，提供商業型不動產逆向抵押貸款服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02000', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '面對人口老化問題，政府在民國98年提出第一期友善關懷老人服務方案，並於102年再推出第二期計畫， 請針對第二期計畫的目標，下列所示何者錯誤？', '["提倡預防保健，促進健康老化", "建置友善環境，促進在地老化", "鼓勵終身學習，促進智慧老化", "推動社會參與，促進活力老化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
